-- 0002_baseline.sql
-- 完整建表 baseline（由 cmd/genmigration 从 ent schema 生成，勿手改）。
-- 改 ent/schema 后运行 `go run ./cmd/genmigration` 重新生成；CI 会 drift 检测。
-- 依赖 pre_0001_pgvector.sql 先安装 vector 扩展（Incident/Postmortem 的 embedding 列用）。
-- migrate.Run 优先用本文件建表；ent auto-migrate 作为兜底补充同步（处理边角差异）。

CREATE TABLE "ai_insights" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "stage" character varying NOT NULL, "type" character varying NOT NULL, "content" jsonb NOT NULL, "confidence" real NOT NULL DEFAULT 0, "evidence" jsonb NULL, "status" character varying NOT NULL DEFAULT 'suggested', "resolved_by" bigint NULL, "resolved_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "incident_ai_insights" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "aiinsight_incident_ai_insights" ON "ai_insights" ("incident_ai_insights");
CREATE INDEX "aiinsight_stage" ON "ai_insights" ("stage");
CREATE INDEX "aiinsight_status" ON "ai_insights" ("status");
CREATE TABLE "api_keys" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "token_hash" character varying NOT NULL, "prefix" character varying NOT NULL, "scope" jsonb NULL, "expires_at" timestamptz NULL, "last_used_at" timestamptz NULL, "status" character varying NOT NULL DEFAULT 'active', "created_at" timestamptz NOT NULL, "user_api_keys" bigint NOT NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "apikey_token_hash" ON "api_keys" ("token_hash");
CREATE INDEX "apikey_status" ON "api_keys" ("status");
CREATE TABLE "action_items" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "description" text NOT NULL, "owner_id" character varying NULL, "due_date" timestamptz NULL, "status" character varying NOT NULL DEFAULT 'open', "tracker_url" character varying NULL, "external_id" character varying NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "postmortem_action_items" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "actionitem_status" ON "action_items" ("status");
CREATE INDEX "actionitem_due_date" ON "action_items" ("due_date");
CREATE INDEX "actionitem_external_id" ON "action_items" ("external_id");
CREATE TABLE "audit_logs" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "actor_user_id" bigint NOT NULL DEFAULT 0, "actor_name" character varying NOT NULL DEFAULT 'system', "action" character varying NOT NULL, "resource_type" character varying NOT NULL, "resource_id" bigint NOT NULL DEFAULT 0, "resource_name" character varying NULL, "result" character varying NOT NULL DEFAULT 'success', "detail" jsonb NULL, "ip" character varying NULL, "user_agent" character varying NULL, "created_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
CREATE INDEX "auditlog_actor_user_id" ON "audit_logs" ("actor_user_id");
CREATE INDEX "auditlog_action" ON "audit_logs" ("action");
CREATE INDEX "auditlog_resource_type_resource_id" ON "audit_logs" ("resource_type", "resource_id");
CREATE INDEX "auditlog_created_at" ON "audit_logs" ("created_at");
CREATE TABLE "credentials" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL DEFAULT 'bearer', "secret_ciphertext" character varying NOT NULL, "config" jsonb NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_credentials" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "credential_name" ON "credentials" ("name");
CREATE TABLE "escalation_policies" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "repeat_times" bigint NOT NULL DEFAULT 0, "levels" jsonb NOT NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_escalation_policies" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "events" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "source_event_id" character varying NOT NULL, "source" character varying NOT NULL, "severity" character varying NOT NULL, "status" character varying NOT NULL, "summary" character varying NOT NULL, "detail" jsonb NULL, "labels" jsonb NULL, "dedup_key" character varying NOT NULL, "received_at" timestamptz NOT NULL, "is_noise" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "event_incident" bigint NULL, "integration_events" bigint NULL, "service_events" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "event_dedup_key" ON "events" ("dedup_key");
CREATE UNIQUE INDEX "event_source_source_event_id_status" ON "events" ("source", "source_event_id", "status");
CREATE INDEX "event_severity_received_at" ON "events" ("severity", "received_at");
CREATE INDEX "event_is_noise" ON "events" ("is_noise");
CREATE TABLE "im_account_bindings" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "platform" character varying NOT NULL, "account_id" character varying NOT NULL, "created_at" timestamptz NOT NULL, "user_im_bindings" bigint NOT NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "imaccountbinding_platform_account_id" ON "im_account_bindings" ("platform", "account_id");
CREATE TABLE "incidents" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "number" character varying NOT NULL, "title" character varying NOT NULL, "severity" character varying NOT NULL, "status" character varying NOT NULL DEFAULT 'triggered', "priority" character varying NOT NULL DEFAULT 'p3', "summary" character varying NULL, "escalated_count" bigint NOT NULL DEFAULT 0, "current_level" bigint NOT NULL DEFAULT 0, "merged_into" character varying NULL, "trigger_type" character varying NOT NULL DEFAULT 'auto', "trigger_source_event_id" character varying NULL, "resolved_at" timestamptz NULL, "postmortem_skipped" boolean NOT NULL DEFAULT false, "acked_at" timestamptz NULL, "closed_at" timestamptz NULL, "embedding" vector(1536) NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "escalation_policy_incidents" bigint NULL, "incident_assignee" bigint NULL, "service_incidents" bigint NULL, "team_incidents" bigint NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "incidents_number_key" ON "incidents" ("number");
CREATE INDEX "incident_status_severity" ON "incidents" ("status", "severity");
CREATE INDEX "incident_team_incidents" ON "incidents" ("team_incidents");
CREATE INDEX "incident_service_incidents" ON "incidents" ("service_incidents");
CREATE INDEX "incident_resolved_at" ON "incidents" ("resolved_at");
CREATE TABLE "incident_actions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "type" character varying NOT NULL, "actor" jsonb NOT NULL, "payload" jsonb NULL, "via" character varying NOT NULL, "result" character varying NOT NULL DEFAULT 'success', "timestamp" timestamptz NOT NULL, "incident_actions" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "incidentaction_incident_actions" ON "incident_actions" ("incident_actions");
CREATE INDEX "incidentaction_timestamp" ON "incident_actions" ("timestamp");
CREATE INDEX "incidentaction_via_timestamp" ON "incident_actions" ("via", "timestamp");
CREATE TABLE "integrations" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "config" jsonb NULL, "token" character varying NOT NULL, "enabled" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "service_integrations" bigint NULL, "team_integrations" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "metrics_snapshots" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "period" character varying NOT NULL DEFAULT 'daily', "period_start" timestamptz NOT NULL, "period_end" timestamptz NOT NULL, "alerts_total" bigint NOT NULL DEFAULT 0, "alerts_notified" bigint NOT NULL DEFAULT 0, "alerts_unrouted" bigint NOT NULL DEFAULT 0, "noise_rate" double precision NOT NULL DEFAULT 0, "incidents_total" bigint NOT NULL DEFAULT 0, "incidents_resolved" bigint NOT NULL DEFAULT 0, "mtta_seconds" double precision NOT NULL DEFAULT 0, "mttr_seconds" double precision NOT NULL DEFAULT 0, "by_severity" jsonb NULL, "by_status" jsonb NULL, "postmortems_total" bigint NOT NULL DEFAULT 0, "postmortems_published" bigint NOT NULL DEFAULT 0, "completion_rate" double precision NOT NULL DEFAULT 0, "created_at" timestamptz NOT NULL, "team_metrics_snapshots" bigint NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "metricssnapshot_period_period_start_team_metrics_snapshots" ON "metrics_snapshots" ("period", "period_start", "team_metrics_snapshots");
CREATE INDEX "metricssnapshot_period_period_start" ON "metrics_snapshots" ("period", "period_start");
CREATE TABLE "notifications" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "channel" character varying NOT NULL, "target" character varying NULL, "user_id" bigint NOT NULL DEFAULT 0, "status" character varying NOT NULL DEFAULT 'pending', "reason" character varying NULL, "level" bigint NOT NULL DEFAULT 0, "severity" character varying NULL, "created_at" timestamptz NOT NULL, "incident_notifications" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "notification_incident_notifications" ON "notifications" ("incident_notifications");
CREATE INDEX "notification_status" ON "notifications" ("status");
CREATE INDEX "notification_channel" ON "notifications" ("channel");
CREATE INDEX "notification_created_at" ON "notifications" ("created_at");
CREATE TABLE "notification_rules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "condition" jsonb NOT NULL, "channels" jsonb NOT NULL, "template_id" character varying NULL, "quiet_hours" jsonb NULL, "enabled" boolean NOT NULL DEFAULT true, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_notification_rules" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "notification_templates" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "channel" character varying NOT NULL, "format" character varying NOT NULL, "title_template" character varying NOT NULL, "body_template" text NOT NULL, "actions" jsonb NULL, "builtin" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_notification_templates" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "overrides" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "start_time" timestamptz NOT NULL, "end_time" timestamptz NOT NULL, "reason" character varying NULL, "created_at" timestamptz NOT NULL, "override_user" bigint NOT NULL, "override_created_by" bigint NULL, "schedule_overrides" bigint NOT NULL, PRIMARY KEY ("id"));
CREATE TABLE "postmortems" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "status" character varying NOT NULL DEFAULT 'draft', "generated_by" character varying NOT NULL DEFAULT 'mixed', "sections" jsonb NOT NULL, "published_at" timestamptz NULL, "embedding" vector(1536) NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "incident_postmortem" bigint NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "postmortems_incident_postmortem_key" ON "postmortems" ("incident_postmortem");
CREATE TABLE "raw_events" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "payload" bytea NOT NULL, "headers" jsonb NULL, "received_at" timestamptz NOT NULL, "status" character varying NOT NULL DEFAULT 'received', "error" text NULL, "created_at" timestamptz NOT NULL, "integration_raw_events" bigint NULL, PRIMARY KEY ("id"));
CREATE INDEX "rawevent_status_received_at" ON "raw_events" ("status", "received_at");
