CREATE UNIQUE INDEX "roles_name_key" ON "roles" ("name");
CREATE TABLE "role_bindings" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "scope_level" character varying NOT NULL, "team_id" character varying NULL, "granted_by" character varying NULL, "expires_at" timestamptz NULL, "source_incident_id" bigint NOT NULL DEFAULT 0, "granted_at" timestamptz NOT NULL, "role_role_bindings" bigint NOT NULL, "user_role_bindings" bigint NOT NULL, PRIMARY KEY ("id"));
CREATE TABLE "rotations" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "shift_length" character varying NOT NULL DEFAULT '24h', "handoff_time" character varying NOT NULL DEFAULT '09:00', "rotation_type" character varying NOT NULL, "start_date" timestamptz NOT NULL, "end_date" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "schedule_rotations" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "runbooks" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "trigger" jsonb NULL, "auto_run" boolean NOT NULL DEFAULT false, "content_markdown" text NULL, "steps" jsonb NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_runbooks" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "schedules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "type" character varying NOT NULL, "timezone" character varying NOT NULL DEFAULT 'Asia/Shanghai', "layers" jsonb NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_schedules" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "services" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "slug" character varying NOT NULL, "description" text NULL, "labels" jsonb NULL, "auto_create_incident" boolean NOT NULL DEFAULT true, "status" character varying NOT NULL DEFAULT 'active', "source" character varying NOT NULL DEFAULT 'manual', "provisioned_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "service_escalation_policy" bigint NULL, "team_services" bigint NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "services_slug_key" ON "services" ("slug");
CREATE INDEX "service_status" ON "services" ("status");
CREATE INDEX "service_source" ON "services" ("source");
CREATE TABLE "subscriptions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "channels" jsonb NULL, "min_severity" character varying NOT NULL DEFAULT 'warning', "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "service_subscriptions" bigint NULL, "team_subscriptions" bigint NULL, "user_subscriptions" bigint NOT NULL, PRIMARY KEY ("id"));
CREATE INDEX "subscription_user_subscriptions" ON "subscriptions" ("user_subscriptions");
CREATE INDEX "subscription_team_subscriptions" ON "subscriptions" ("team_subscriptions");
CREATE INDEX "subscription_service_subscriptions" ON "subscriptions" ("service_subscriptions");
CREATE TABLE "suppression_rules" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "kind" character varying NOT NULL DEFAULT 'adhoc', "match_labels" jsonb NOT NULL, "time_window" jsonb NULL, "severity_filter" jsonb NULL, "action" character varying NOT NULL DEFAULT 'suppress', "reduce_to" character varying NULL, "preserve_critical" boolean NOT NULL DEFAULT true, "enabled" boolean NOT NULL DEFAULT true, "source" character varying NOT NULL DEFAULT 'manual', "source_insight_id" bigint NULL, "expires_at" timestamptz NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_suppression_rules" bigint NULL, PRIMARY KEY ("id"));
CREATE TABLE "teams" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "name" character varying NOT NULL, "slug" character varying NOT NULL, "description" text NULL, "parent_team_id" character varying NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "team_default_escalation_policy" bigint NULL, PRIMARY KEY ("id"));
